class Solution {
public:
    vector<int> dailyTemperatures(vector<int>& temperatures) {
        int n = temperatures.size();
        vector<int> ans(n);
        stack<int> s; // 存下标，栈内温度从底到顶递减：都是还没等到更高温度的日子
        for (int i = 0; i < n; ++i) {
            while (!s.empty() && temperatures[i] > temperatures[s.top()]) {
                int previousIndex = s.top();
                ans[previousIndex] = i - previousIndex; // i 是它右边第一个更高温度的下标
                s.pop();
            }
            s.push(i);
        }
        return ans;
    }
};
